package com.example.demo.controller;

import org.springframework.beans.factory.annotation.Autowired;
import org.springframework.http.ResponseEntity;
import org.springframework.web.bind.annotation.GetMapping;
import org.springframework.web.bind.annotation.RequestParam;
import org.springframework.web.bind.annotation.RestController;

import java.util.List;
import java.util.Map;

@RestController
public class ProductController {

    @Autowired
    private org.springframework.jdbc.core.JdbcTemplate jdbcTemplate;

    @GetMapping("/products/search")
    public ResponseEntity<List<Map<String, Object>>> searchProducts(@RequestParam("name") String name) {
        String sql = "SELECT id, name, price, description FROM products WHERE name LIKE ?";
        List<Map<String, Object>> products = jdbcTemplate.queryForList(sql, "%" + name + "%");
        return ResponseEntity.ok(products);
    }
}